    private boolean handleTeleport(CommandSender sender, String[] args) {
        if (!(sender instanceof Player player)) {
            sender.sendMessage("Only players can use this command.");
            return true;
        }

        if (args.length < 2) {
            sender.sendMessage("Usage: /pvpbot tp <botName>");
            return true;
        }

        String name = args[1];
        NPC npc = findPvPBotByName(name);
        if (npc == null || !npc.isSpawned()) {
            sender.sendMessage("§c[PvPBot] PvPBot named '" + name + "' is not active or spawned!");
            return true;
        }

        player.teleport(npc.getEntity().getLocation());
        sender.sendMessage("Teleported to PvPBot '" + name + "'");
        return true;
    }

    private NPC findPvPBotByName(String name) {
        for (NPC npc : CitizensAPI.getNPCRegistry()) {
            if (npc.hasTrait(PvPBotTrait.class) && npc.getName().equalsIgnoreCase(name)) {
                return npc;
            }
        }
        return null;
    }

    @Override
    public List<String> onTabComplete(CommandSender sender, Command command, String alias, String[] args) {
        if (args.length == 1) {
            String partial = args[0].toLowerCase();
            return List.of("spawn", "remove", "removeall", "tp").stream()
                    .filter(s -> s.startsWith(partial))
                    .toList();
        }

        if (args.length == 2) {
            String sub = args[0].toLowerCase();
            if (sub.equals("tp") || sub.equals("remove")) {
                String partial = args[1].toLowerCase();
                return CitizensAPI.getNPCRegistry().stream()
                        .filter(n -> n.hasTrait(PvPBotTrait.class) && n.isSpawned())
                        .map(NPC::getName)
                        .filter(n -> n.toLowerCase().startsWith(partial))
                        .toList();
            }
        }

        return List.of();
    }
}

