        }

        if (args.length < 2) {
            sender.sendMessage("Usage: /pvpbot tp <botName>");
            return true;
        }

        String name = args[1];
        NPC npc = findPvPBotByName(name);
        if (npc == null || !npc.isSpawned()) {
            sender.sendMessage("§c[PvPBot] PvPBot named '" + name + "' is not active or spawned!");
            return true;
        }

        player.teleport(npc.getEntity().getLocation());
        sender.sendMessage("Teleported to PvPBot '" + name + "'");
        return true;
    }

    private NPC findPvPBotByName(String name) {
        for (NPC npc : CitizensAPI.getNPCRegistry()) {
            if (npc.hasTrait(PvPBotTrait.class) && npc.getName().equalsIgnoreCase(name)) {
                return npc;
            }
        }
        return null;
    }

