         for (NPC npc : CitizensAPI.getNPCRegistry()) {
             if (npc.hasTrait(PvPBotTrait.class) && npc.getName().equalsIgnoreCase(name)) {
                 return npc;
             }
         }
         return null;
     }

     @Override
     public List<String> onTabComplete(CommandSender sender, Command command, String alias, String[] args) {
         if (args.length == 1) {
             String partial = args[0].toLowerCase();
-            return List.of("spawn", "remove", "removeall", "tp").stream()
+            return List.of("spawn", "remove", "removeall").stream()
                     .filter(s -> s.startsWith(partial))
                     .toList();
         }

         if (args.length == 2) {
             String sub = args[0].toLowerCase();
-            if (sub.equals("tp") || sub.equals("remove")) {
+            if (sub.equals("remove")) {
                 String partial = args[1].toLowerCase();
                 List<String> activeBotNames = new ArrayList<>();
                 for (NPC npc : CitizensAPI.getNPCRegistry()) {
                     if (npc.hasTrait(PvPBotTrait.class) && npc.isSpawned()) {
                         String name = npc.getName();
                         if (name.toLowerCase().startsWith(partial)) {
                             activeBotNames.add(name);
                         }
                     }
                 }
                 return activeBotNames;
             }
         }

         return List.of();
     }
 }

