new BukkitRunnable() {
    @Override
    public void run() {
        if (finalNpc.isSpawned()) {
            finalNpc.despawn();
        }
        boolean spawned = finalNpc.spawn(finalLoc);
        if (!spawned) {
            JavaPlugin.getPlugin(PvPBot.class).getLogger().warning(
                "Failed to respawn " + finalNpc.getName() + " (ID: " + finalNpc.getId()
                + ") at unsafe location: " + finalLoc);
            finalNpc.destroy();
            return;
        }
        if (finalNpc.getEntity() instanceof Player player) {
            player.setHealth(player.getAttribute(Attribute.GENERIC_MAX_HEALTH).getValue());
            player.setFoodLevel(20);
            player.setFireTicks(0);
            player.setFallDistance(0.0F);
        }
    }
}.runTaskLater(plugin, 10);

