+                    player.setHealth(player.getAttribute(Attribute.MAX_HEALTH).getValue());
                     player.setFoodLevel(20);
                     player.setFireTicks(0);
                     player.setFallDistance(0.0F);
                 }
             }
         }.runTaskLater(plugin, 10);
     }
 }

