+// Phase 3: Core Melee Combat AI — Target Selector
+package com.khoablabla.pvpbot.combat;
+
+import net.citizensnpcs.api.npc.NPC;
+
+import org.bukkit.GameMode;
+import org.bukkit.Location;
+import org.bukkit.entity.Entity;
+import org.bukkit.entity.LivingEntity;
+import org.bukkit.entity.Player;
+import org.bukkit.scoreboard.Team;
+
+import java.util.Comparator;
+
+public final class CombatTargetSelector {
+
+    private CombatTargetSelector() {
+    }
+
+    public static LivingEntity findTarget(NPC npc, double range) {
+        if (!(npc.getEntity() instanceof LivingEntity botEntity)) return null;
+
+        Location botLoc = botEntity.getLocation();
+        return botEntity.getNearbyEntities(range, range, range).stream()
+            .filter(e -> e instanceof LivingEntity le && !le.isDead() && !e.equals(botEntity))
+            .filter(e -> {
+                if (!(e instanceof Player p)) return true;
+                GameMode gm = p.getGameMode();
+                return gm == GameMode.SURVIVAL || gm == GameMode.ADVENTURE;
+            })
+            .filter(e -> {
+                if (!(e instanceof Player targetPlayer) || !(botEntity instanceof Player botPlayer)) return true;
+                Team botTeam = botPlayer.getScoreboard().getEntityTeam(botPlayer);
+                Team targetTeam = botPlayer.getScoreboard().getEntityTeam(targetPlayer);
+                return botTeam == null || !botTeam.equals(targetTeam);
+            })
+            .map(e -> (LivingEntity) e)
+            .filter(e -> e.getLocation().distanceSquared(botLoc) <= range * range)
+            .min(Comparator.comparingDouble(e -> e.getLocation().distanceSquared(botLoc)))
+            .orElse(null);
+    }
+}

