// Phase 1: Citizens Trait Base Lifecycle
// Phase 2: Tablist & Player Simulation
// Phase 3: Core Melee Combat AI Integration
package com.khoablabla.pvpbot.traits;

import net.citizensnpcs.api.npc.NPC;
import net.citizensnpcs.api.trait.Trait;

import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Player;
import org.bukkit.plugin.java.JavaPlugin;

import com.khoablabla.pvpbot.PvPBot;
import com.khoablabla.pvpbot.combat.CombatTargetSelector;
import com.khoablabla.pvpbot.combat.MeleeAttackController;
import com.khoablabla.pvpbot.movement.BotMovementController;

public class PvPBotTrait extends Trait {

    private int tickCounter = 0;
    private int idleTickCounter = 0;
    private int lastDamageTick = 0;
    private LivingEntity target = null;
    private final BotMovementController movementController = new BotMovementController();
    private final MeleeAttackController attackController = new MeleeAttackController();
    private static final double TARGET_RANGE = 16.0;

    public PvPBotTrait() {
        super("pvpbot");
    }

    public void setTarget(LivingEntity newTarget) {
        this.target = newTarget;
        if (newTarget != null) {
            lastDamageTick = tickCounter;
        }
    }

    @Override
    public void onAttach() {
        if (npc.getEntity() instanceof Player) {
            JavaPlugin plugin = JavaPlugin.getPlugin(PvPBot.class);
            plugin.getLogger().info("PvPBotTrait attached to NPC " + npc.getName() + " (ID: " + npc.getId() + ")");
        } else if (npc.getEntity() != null) {
            JavaPlugin plugin = JavaPlugin.getPlugin(PvPBot.class);
            plugin.getLogger().warning("PvPBotTrait attached to NPC " + npc.getName()
                    + " (ID: " + npc.getId() + ") but its entity is not a Player — PvP functionality may be limited.");
        }
    }

    @Override
    public void onSpawn() {
        if (npc.getEntity() instanceof Player player) {
            npc.setProtected(false);
            npc.data().set(NPC.Metadata.DAMAGE_OTHERS, true);

            JavaPlugin plugin = JavaPlugin.getPlugin(PvPBot.class);
            plugin.getLogger().info("PvPBot NPC '" + npc.getName() + "' (ID: " + npc.getId()
                    + ") has spawned in world: " + player.getWorld().getName());
        }
    }

    @Override
    public void onDespawn() {
        JavaPlugin plugin = JavaPlugin.getPlugin(PvPBot.class);
        plugin.getLogger().info("PvPBot NPC (ID: " + npc.getId() + ") has despawned from world.");
    }

    @Override
    public void run() {
        tickCounter++;

        if (tickCounter % 10 == 0) {
            target = CombatTargetSelector.validateTarget(npc, TARGET_RANGE, target, tickCounter, lastDamageTick);
        }

        if (target != null && !target.isDead() && target.isValid()) {
            movementController.handleMovement(npc, target, tickCounter);
            attackController.handleAttack(npc, target);
            idleTickCounter = 0;
        } else {
            target = null;
            npc.getNavigator().cancelNavigation();

            idleTickCounter++;
            if (idleTickCounter >= 100) {
                idleTickCounter = 0;
                movementController.handleIdleWander(npc);
            }
        }
    }
}

// Phase 3: Core Melee Combat AI — Pursuit Navigation, Bunny Hop & Idle Wander
package com.khoablabla.pvpbot.movement;

import net.citizensnpcs.api.npc.NPC;

import org.bukkit.Location;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Player;
import org.bukkit.util.Vector;

import com.khoablabla.pvpbot.utils.SafeLocationFinder;

import java.util.Random;

public class BotMovementController {

    private int lastBHopTick = 0;
    private final Random random = new Random();

    public void handleMovement(NPC npc, LivingEntity target, int currentTick) {
        if (npc.getEntity() == null) return;

        npc.getNavigator().setTarget(target, true);

        if (!(npc.getEntity() instanceof Player botPlayer)) return;
        if (currentTick - lastBHopTick < 20) return;
        lastBHopTick = currentTick;

        if (botPlayer.getLocation().distance(target.getLocation()) <= 5.0) return;

        Location below = botPlayer.getLocation().subtract(0, 0.01, 0);
        if (below.getBlock().isSolid()) {
            Vector currentVel = botPlayer.getVelocity();
            botPlayer.setVelocity(new Vector(currentVel.getX(), 0.42, currentVel.getZ()));
        }
    }

    public void handleIdleWander(NPC npc) {
        if (!(npc.getEntity() instanceof Player botPlayer)) return;
        if (npc.getNavigator().isNavigating()) return;

        Location origin = botPlayer.getLocation();
        for (int attempt = 0; attempt < 5; attempt++) {
            double dx = (random.nextDouble() - 0.5) * 10;
            double dz = (random.nextDouble() - 0.5) * 10;
            Location candidate = origin.clone().add(dx, 0, dz);
            Location safe = SafeLocationFinder.findSafeLocation(candidate);
            if (safe != null) {
                npc.getNavigator().setTarget(safe);
                return;
            }
        }
    }
}

// Phase 3: Core Melee Combat AI — Melee Attack Loop & Jump Criticals
package com.khoablabla.pvpbot.combat;

import net.citizensnpcs.api.npc.NPC;

import org.bukkit.Location;
import org.bukkit.Particle;
import org.bukkit.entity.LivingEntity;
import org.bukkit.entity.Player;
import org.bukkit.util.Vector;

public class MeleeAttackController {

    private int cooldownTicks = 0;
    private boolean jumpTriggered = false;
    private boolean criticalsEnabled = true;

    private static final double ATTACK_RANGE = 3.0;
    private static final double JUMP_VELOCITY = 0.42;
    private static final int SWORD_COOLDOWN = 12;
    private static final double NORMAL_DAMAGE = 2.0;
    private static final double CRITICAL_DAMAGE = 4.0;

    public void handleAttack(NPC npc, LivingEntity target) {
        if (cooldownTicks > 0) cooldownTicks--;

        if (!(npc.getEntity() instanceof Player botPlayer)) return;

        double dist = botPlayer.getLocation().distance(target.getLocation());

        if (dist > ATTACK_RANGE) {
            jumpTriggered = false;
            return;
        }

        if (cooldownTicks > 0) return;

        if (criticalsEnabled) {
            if (!jumpTriggered) {
                Location below = botPlayer.getLocation().subtract(0, 0.01, 0);
                if (!below.getBlock().isSolid()) return;
                Vector currentVel = botPlayer.getVelocity();
                botPlayer.setVelocity(new Vector(currentVel.getX(), JUMP_VELOCITY, currentVel.getZ()));
                jumpTriggered = true;
            }
            if (botPlayer.getVelocity().getY() < 0) {
                executeStrike(botPlayer, target, true);
                jumpTriggered = false;
                cooldownTicks = SWORD_COOLDOWN;
            }
        } else {
            executeStrike(botPlayer, target, false);
            cooldownTicks = SWORD_COOLDOWN;
        }
    }

    private void executeStrike(Player botPlayer, LivingEntity target, boolean critical) {
        Location targetLoc = target.getLocation().add(0, 1, 0);
        if (critical) {
            target.getWorld().spawnParticle(Particle.CRIT, targetLoc, 15, 0.5, 0.5, 0.5, 0.1);
        }
        botPlayer.swingMainHand();
        target.damage(critical ? CRITICAL_DAMAGE : NORMAL_DAMAGE, botPlayer);
    }
}

